import numpy as np
from typing import List, Tuple, Optional

class Lattice:
    def __init__(self, basis: np.ndarray):
        self.basis = np.array(basis, dtype=float)

        if self.basis.ndim != 2:
            raise ValueError("Basis must be a 2D matrix")

        # Check linear independence
        rank = np.linalg.matrix_rank(self.basis)
        if rank != self.basis.shape[1]:
            raise ValueError("Basis vectors must be linearly independent")

        self._dimension = self.basis.shape[0]
        self._rank = self.basis.shape[1]

    @property
    def dimension(self) -> int:
        return self._dimension

    @property
    def rank(self) -> int:
        return self._rank

    def determinant(self) -> float:
        if self._dimension == self._rank:
            return abs(np.linalg.det(self.basis))
        else:
            gram = self.basis.T @ self.basis
            return np.sqrt(np.linalg.det(gram))

    def contains(self, v: np.ndarray, tolerance: float = 1e-9) -> bool:
        v = np.array(v, dtype=float)
        if len(v) != self._dimension:
            return False

        if self._dimension == self._rank:
            coeffs = np.linalg.solve(self.basis, v)
        else:
            coeffs, residuals, rank, s = np.linalg.lstsq(self.basis, v, rcond=None)
            if len(residuals) > 0 and residuals[0] > tolerance:
                return False

        return np.allclose(coeffs, np.round(coeffs), atol=tolerance)

    def gram_matrix(self) -> np.ndarray:
        return self.basis.T @ self.basis

    def hadamard_ratio(self) -> float:
        det = self.determinant()
        norms_product = np.prod([np.linalg.norm(self.basis[:, i]) 
                                 for i in range(self._rank)])
        return det / norms_product if norms_product > 0 else 0.0

import numpy as np
from typing import Tuple

def gram_schmidt(B: np.ndarray) -> Tuple[np.ndarray, np.ndarray]:
    B = np.array(B, dtype=float)
    n, m = B.shape

    B_star = np.zeros_like(B)
    mu = np.zeros((m, m))

    for i in range(m):
        B_star[:, i] = B[:, i].copy()

        for j in range(i):
            # μ[i,j] = <b_i, b_j*> / <b_j*, b_j*>
            if np.dot(B_star[:, j], B_star[:, j]) > 1e-10:
                mu[i, j] = np.dot(B[:, i], B_star[:, j]) / np.dot(B_star[:, j], B_star[:, j])
                B_star[:, i] -= mu[i, j] * B_star[:, j]

    # Set diagonal of mu to 1 (convention)
    np.fill_diagonal(mu, 1.0)

    return B_star, mu

def verify_gram_schmidt(B: np.ndarray, B_star: np.ndarray, mu: np.ndarray) -> bool:
    n, m = B.shape
    tol = 1e-9

    # Check orthogonality of B*
    for i in range(m):
        for j in range(i):
            dot = np.dot(B_star[:, i], B_star[:, j])
            if abs(dot) > tol:
                return False

    # Check reconstruction: b_i = b_i* + Σ μ[i,j] * b_j*
    for i in range(m):
        reconstructed = B_star[:, i].copy()
        for j in range(i):
            reconstructed += mu[i, j] * B_star[:, j]
        if not np.allclose(B[:, i], reconstructed, atol=tol):
            return False

    return True

def compute_gram_schmidt_norms(B: np.ndarray) -> np.ndarray:
    B_star, _ = gram_schmidt(B)
    m = B.shape[1]
    return np.array([np.dot(B_star[:, i], B_star[:, i]) for i in range(m)])

import numpy as np
from typing import Tuple

def gram_schmidt_for_lll(B: np.ndarray) -> Tuple[np.ndarray, np.ndarray]:
    """Gram-Schmidt with μ matrix for LLL."""
    B = np.array(B, dtype=float)
    n, m = B.shape
    B_star = np.zeros_like(B)
    mu = np.zeros((m, m))

    for i in range(m):
        B_star[:, i] = B[:, i].copy()
        for j in range(i):
            norm_sq = np.dot(B_star[:, j], B_star[:, j])
            if norm_sq > 1e-10:
                mu[i, j] = np.dot(B[:, i], B_star[:, j]) / norm_sq
                B_star[:, i] -= mu[i, j] * B_star[:, j]
    return B_star, mu

def lll_reduce(B: np.ndarray, delta: float = 0.75) -> np.ndarray:
    B = np.array(B, dtype=float)
    n, m = B.shape

    k = 1
    while k < m:
        B_star, mu = gram_schmidt_for_lll(B)

        # Size reduction for b_k
        for j in range(k - 1, -1, -1):
            if abs(mu[k, j]) > 0.5:
                B[:, k] -= round(mu[k, j]) * B[:, j]
                B_star, mu = gram_schmidt_for_lll(B)

        # Lovász condition
        norm_k = np.dot(B_star[:, k], B_star[:, k])
        norm_k1 = np.dot(B_star[:, k-1], B_star[:, k-1])

        if norm_k >= (delta - mu[k, k-1]**2) * norm_k1:
            k += 1
        else:
            # Swap b_k and b_{k-1}
            B[:, [k, k-1]] = B[:, [k-1, k]]
            k = max(k - 1, 1)

    return B

def is_lll_reduced(B: np.ndarray, delta: float = 0.75) -> Tuple[bool, str]:
    B_star, mu = gram_schmidt_for_lll(B)
    m = B.shape[1]
    tol = 1e-9

    # Check size reduction
    for i in range(m):
        for j in range(i):
            if abs(mu[i, j]) > 0.5 + tol:
                return False, f'Size violation: |μ[{i},{j}]| = {abs(mu[i,j]):.4f} > 0.5'

    # Check Lovász condition
    for k in range(1, m):
        norm_k = np.dot(B_star[:, k], B_star[:, k])
        norm_k1 = np.dot(B_star[:, k-1], B_star[:, k-1])
        lhs = norm_k
        rhs = (delta - mu[k, k-1]**2) * norm_k1
        if lhs < rhs - tol:
            return False, f'Lovász violation at k={k}'

    return True, 'OK'

def lll_quality_improvement(B_original: np.ndarray, B_reduced: np.ndarray) -> dict:
    def basis_stats(B):
        norms = [np.linalg.norm(B[:, i]) for i in range(B.shape[1])]
        det = abs(np.linalg.det(B)) if B.shape[0] == B.shape[1] else np.sqrt(np.linalg.det(B.T @ B))
        hadamard = det / np.prod(norms)
        return {'min_norm': min(norms), 'max_norm': max(norms), 'hadamard': hadamard}

    orig = basis_stats(B_original)
    red = basis_stats(B_reduced)

    return {
        'original': orig,
        'reduced': red,
        'shortest_improvement': orig['min_norm'] / red['min_norm'],
        'hadamard_improvement': red['hadamard'] / orig['hadamard']
    }
